const fs = require('fs');
const path = require('path');
const { execFileSync } = require('child_process');

// ── Parameters ──────────────────────────────────────────────────
const params = $('Set Global Parameters').first().json;
const testCardFilter = (params.TestCardFilter || '').trim();
const frameDuration = parseFloat(params.FrameDuration || '0.333');

const raw = $input.first().json;
const deck = raw.data !== undefined ? raw.data : raw;

const deckDir = ((deck.Assets && deck.Assets.Directory)
  ? deck.Assets.Directory
  : 'D:/data/cards/Standard').replace(/\\+/g, '/').replace(/\//g, path.sep);

const cardRefs = deck.Cards;
if (!cardRefs || cardRefs.length === 0) {
  throw new Error('[Movie] No Cards found in Deck.json.');
}

const filteredCards = testCardFilter
  ? cardRefs.filter(c => c.Card === testCardFilter)
  : cardRefs;

if (filteredCards.length === 0) {
  throw new Error(
    '[Movie] No cards matched filter: ' + JSON.stringify(testCardFilter) +
    '. Check that TestCardFilter matches a Card name in Deck.json.'
  );
}

const OUT_SIZE = 512;
const results = { processed: 0, skipped: 0, failed: 0, cards: [] };

for (const cardRef of filteredCards) {
  const cardName = cardRef.Card;
  const cardFilePath = path.join(deckDir, cardRef.File.replace(/\//g, path.sep));

  // Read card JSON
  let cardRaw;
  try {
    cardRaw = JSON.parse(fs.readFileSync(cardFilePath, 'utf8').replace(/^\uFEFF/, ''));
  } catch (e) {
    console.warn('[Movie] Cannot read card: ' + cardName + ': ' + e.message);
    results.failed++;
    results.cards.push({ card: cardName, status: 'failed', reason: 'Cannot read card file: ' + e.message });
    continue;
  }

  const card = cardRaw['data.Cards'] || cardRaw;
  const cardDir = (card.Directory || path.join(deckDir, 'Cards'))
    .replace(/\\+/g, '/').replace(/\//g, path.sep);

  // Get ReversedImage from top-level Assets
  const reversedImageName = card.Assets && card.Assets.ReversedImage;
  if (!reversedImageName) {
    results.skipped++;
    results.cards.push({ card: cardName, status: 'skipped', reason: 'No Assets.ReversedImage' });
    continue;
  }

  // Find reversed record
  const reversedRecord = (card.records || []).find(r => r.Orientation === 'reversed');
  if (!reversedRecord) {
    results.skipped++;
    results.cards.push({ card: cardName, status: 'skipped', reason: 'No reversed record' });
    continue;
  }

  const cardImageName = reversedRecord.Assets && reversedRecord.Assets.CardImage;
  const movieName = reversedRecord.Assets && reversedRecord.Assets.Movie;

  if (!cardImageName) {
    results.skipped++;
    results.cards.push({ card: cardName, status: 'skipped', reason: 'No CardImage in reversed record' });
    continue;
  }
  if (!movieName) {
    results.skipped++;
    results.cards.push({ card: cardName, status: 'skipped', reason: 'No Movie in reversed record' });
    continue;
  }

  // Build slug: spaces → underscores, parentheses removed
  const slug = cardName.replace(/[()]/g, '').replace(/\s+/g, '_');

  // Build ordered frame list:
  //   1. ReversedImage (needs resize to 512x512)
  //   2. FOCUST_REVERSED_XXX_00 through _05
  //   3. CardImage
  //   4. FOCUS_REVERSED_XXX_07 through _14
  const frameEntries = [];
  const missing = [];

  // Frame 1: ReversedImage
  const reversedImagePath = path.join(cardDir, reversedImageName);
  if (fs.existsSync(reversedImagePath)) {
    frameEntries.push({ path: reversedImagePath, resize: true });
  } else {
    missing.push(reversedImageName);
  }

  // Frames 2-7: FOCUST_REVERSED_XXX_00 through _05
  for (let i = 0; i <= 5; i++) {
    const fn = 'FOCUST_REVERSED_' + slug + '_' + String(i).padStart(2, '0') + '.png';
    const fp = path.join(cardDir, fn);
    if (fs.existsSync(fp)) {
      frameEntries.push({ path: fp, resize: false });
    } else {
      missing.push(fn);
    }
  }

  // Frame 8: CardImage
  const cardImagePath = path.join(cardDir, cardImageName);
  if (fs.existsSync(cardImagePath)) {
    frameEntries.push({ path: cardImagePath, resize: false });
  } else {
    missing.push(cardImageName);
  }

  // Frames 9-16: FOCUS_REVERSED_XXX_07 through _14
  for (let i = 7; i <= 14; i++) {
    const fn = 'FOCUS_REVERSED_' + slug + '_' + String(i).padStart(2, '0') + '.png';
    const fp = path.join(cardDir, fn);
    if (fs.existsSync(fp)) {
      frameEntries.push({ path: fp, resize: false });
    } else {
      missing.push(fn);
    }
  }

  if (missing.length > 0) {
    results.skipped++;
    results.cards.push({
      card: cardName,
      status: 'skipped',
      reason: 'Missing ' + missing.length + ' frame(s): ' + missing.join(', ')
    });
    continue;
  }

  // Check if movie already exists
  const moviePath = path.join(cardDir, movieName);
  if (fs.existsSync(moviePath)) {
    results.skipped++;
    results.cards.push({ card: cardName, status: 'skipped', reason: 'Movie already exists: ' + movieName });
    continue;
  }

  // Create temp directory for intermediate files
  const tempDir = path.join(cardDir, '_temp_movie_reversed');
  fs.mkdirSync(tempDir, { recursive: true });

  try {
    const concatLines = [];

    for (let f = 0; f < frameEntries.length; f++) {
      let framePath = frameEntries[f].path;

      if (frameEntries[f].resize) {
        // Resize ReversedImage to OUT_SIZE x OUT_SIZE
        const tempPath = path.join(tempDir, 'resized_' + f + '.png');
        execFileSync('ffmpeg', [
          '-y', '-i', framePath,
          '-vf', 'scale=' + OUT_SIZE + ':' + OUT_SIZE,
          tempPath
        ], { encoding: 'utf8', stdio: 'pipe' });
        framePath = tempPath;
      }

      concatLines.push("file '" + framePath.replace(/\\/g, '/') + "'");
      concatLines.push('duration ' + frameDuration.toFixed(3));
    }

    // Write concat list file
    const concatPath = path.join(tempDir, 'concat.txt');
    fs.writeFileSync(concatPath, concatLines.join('\n'), 'utf8');

    // Generate movie with ffmpeg
    fs.mkdirSync(path.dirname(moviePath), { recursive: true });
    execFileSync('ffmpeg', [
      '-y',
      '-f', 'concat',
      '-safe', '0',
      '-i', concatPath,
      '-vf', 'format=yuv420p',
      '-c:v', 'mpeg2video',
      '-b:v', '5M',
      moviePath
    ], { encoding: 'utf8', stdio: 'pipe' });

    // Clean up temp directory
    const tempFiles = fs.readdirSync(tempDir);
    for (const tf of tempFiles) {
      fs.unlinkSync(path.join(tempDir, tf));
    }
    fs.rmdirSync(tempDir);

    results.processed++;
    results.cards.push({
      card: cardName,
      status: 'generated',
      movie: movieName,
      moviePath: moviePath,
      totalFrames: frameEntries.length,
      frameDuration: frameDuration
    });

  } catch (e) {
    // Clean up temp directory on failure
    try {
      const tempFiles = fs.readdirSync(tempDir);
      for (const tf of tempFiles) fs.unlinkSync(path.join(tempDir, tf));
      fs.rmdirSync(tempDir);
    } catch (ignore) {}

    results.failed++;
    results.cards.push({
      card: cardName,
      status: 'failed',
      reason: 'ffmpeg error: ' + (e.stderr || e.message)
    });
  }
}

if (results.processed === 0 && results.failed === 0 && results.skipped === 0) {
  throw new Error(
    '[Movie] No cards processed. Check TestCardFilter and Deck.json Cards array.'
  );
}

return [{ json: results }];
